import { SPELL_EN } from './spells-en'

// Curated, hand-translated Russian spells — the offline primary source for the
// Spells section. Dice are in "к" notation so Quick Roll works. Extend freely.

interface P {
  key: string
  name: string
  level: number
  school: string
  time?: string
  range?: string
  comp?: string
  duration?: string
  conc?: boolean
  ritual?: boolean
  classes?: string[]
  desc: string
  higher?: string
}

function sp(p: P): Spell {
  return {
    key: p.key,
    name: p.name,
    level: p.level,
    school: p.school,
    desc: p.desc,
    higherLevel: p.higher,
    rangeText: p.range,
    castingTime: p.time ?? '1 действие',
    duration: p.duration ?? 'Мгновенная',
    components: p.comp ?? 'В, С',
    concentration: Boolean(p.conc),
    ritual: Boolean(p.ritual),
    classes: p.classes ?? []
  }
}

